(function () {
  "use strict";

  if (window.htmx) return;

  function dispatchAfterSwap(detail) {
    document.body.dispatchEvent(new CustomEvent("htmx:afterSwap", {
      bubbles: true,
      detail: detail
    }));
  }

  function resolveTarget(elt) {
    var selector = elt.getAttribute("hx-target");
    if (!selector) return elt;
    return document.querySelector(selector);
  }

  function performSwap(target, html, triggerElt, url) {
    target.innerHTML = html;

    dispatchAfterSwap({
      target: target,
      elt: triggerElt,
      requestConfig: { path: url }
    });
  }

  function runTransitionSwap(target, html, triggerElt, url) {
    var useTransitions = !!window.htmx.config.globalViewTransitions;
    var canTransition = useTransitions && typeof document.startViewTransition === "function";

    if (!canTransition) {
      performSwap(target, html, triggerElt, url);
      return;
    }

    document.startViewTransition(function () {
      performSwap(target, html, triggerElt, url);
    });
  }

  function requestFragment(triggerElt, url, pushUrl) {
    var target = resolveTarget(triggerElt);
    if (!target) return;

    fetch(url, {
      method: "GET",
      headers: {
        "HX-Request": "true",
        "X-Requested-With": "XMLHttpRequest"
      },
      credentials: "same-origin"
    })
      .then(function (response) {
        if (!response.ok) throw new Error("Request failed");
        return response.text();
      })
      .then(function (html) {
        runTransitionSwap(target, html, triggerElt, url);
        if (pushUrl) {
          history.pushState({ hx: true }, "", url);
        }
      })
      .catch(function () {
        window.location.href = url;
      });
  }

  function isModifiedClick(event) {
    return event.metaKey || event.ctrlKey || event.shiftKey || event.altKey || event.button !== 0;
  }

  document.addEventListener("click", function (event) {
    var triggerElt = event.target && event.target.closest ? event.target.closest("[hx-get]") : null;
    if (!triggerElt) return;
    if (isModifiedClick(event)) return;

    var url = triggerElt.getAttribute("hx-get");
    if (!url) return;

    event.preventDefault();

    var pushAttr = triggerElt.getAttribute("hx-push-url");
    var pushUrl = pushAttr === "true" || pushAttr === "1";
    requestFragment(triggerElt, url, pushUrl);
  });

  window.addEventListener("popstate", function () {
    var main = document.getElementById("main-content");
    if (!main) return;

    fetch(window.location.pathname, {
      method: "GET",
      headers: {
        "HX-Request": "true",
        "X-Requested-With": "XMLHttpRequest"
      },
      credentials: "same-origin"
    })
      .then(function (response) {
        if (!response.ok) throw new Error("Request failed");
        return response.text();
      })
      .then(function (html) {
        runTransitionSwap(main, html, main, window.location.pathname);
      })
      .catch(function () {
        window.location.reload();
      });
  });

  window.htmx = {
    config: {
      globalViewTransitions: !!window.__MAXMODE_VIEW_TRANSITIONS__
    }
  };
})();
